+/// Try to reduce signed division by power-of-2 to an arithmetic shift right.
 /// Try to reduce signed division by power-of-2 to an arithmetic shift right.
 static Instruction *foldAddToAshr(BinaryOperator &Add) {
   // Division must be by power-of-2, but not the minimum signed value.
@@ -1236,19 +1237,34 @@ static Instruction *foldAddToAshr(BinaryOperator &Add) {
   // Rounding is done by adding -1 if the dividend (X) is negative and has any
   // low bits set. The canonical pattern for that is an "ugt" compare with SMIN:
   // sext (icmp ugt (X & (DivC - 1)), SMIN)
+  // Also accept "eq" compare with the full mask, but only for division by 2:
+  // sext (icmp eq (X & (SMin | (DivC - 1))), (SMin | (DivC - 1)))
+  // The "eq" pattern only works for DivC=2 because it requires all low bits
+  // to be set, which is equivalent to "any low bit set" only when there's one bit.
   const APInt *MaskC;
   ICmpInst::Predicate Pred;
   if (!match(Add.getOperand(1),
              m_SExt(m_ICmp(Pred, m_And(m_Specific(X), m_APInt(MaskC)),
                            m_SignMask()))) ||
-      Pred != ICmpInst::ICMP_UGT)
-    return nullptr;
+      Pred != ICmpInst::ICMP_UGT) {
+    // Try the alternate pattern: icmp eq (X & Mask), Mask
+    // Only valid for division by 2 (when DivC - 1 has only one bit)
+    if (*DivC != 2)
+      return nullptr;
+    const APInt *MaskC2;
+    if (!match(Add.getOperand(1),
+               m_SExt(m_ICmp(Pred, m_And(m_Specific(X), m_APInt(MaskC2)),
+                             m_APInt(MaskC)))) ||
+        Pred != ICmpInst::ICMP_EQ)
+      return nullptr;
+  }

   APInt SMin = APInt::getSignedMinValue(Add.getType()->getScalarSizeInBits());
   if (*MaskC != (SMin | (*DivC - 1)))
     return nullptr;

   // (X / DivC) + sext ((X & (SMin | (DivC - 1)) >u SMin) --> X >>s log2(DivC)
+  // (X / DivC) + sext ((X & (SMin | (DivC - 1)) == (SMin | (DivC - 1))) --> X >>s log2(DivC)
   return BinaryOperator::CreateAShr(
       X, ConstantInt::get(Add.getType(), DivC->exactLogBase2()));
 }

